250		void execute(std::istream *&f, std::string filename, std::vector<std::string> args, RTLIL::Design *design) override
251		{
252			bool flag_nodisplay = false;
253			bool flag_dump_ast1 = false;
254			bool flag_dump_ast2 = false;
255			bool flag_no_dump_ptr = false;
256			bool flag_dump_vlog1 = false;
257			bool flag_dump_vlog2 = false;
258			bool flag_dump_rtlil = false;
259			bool flag_debug_lexer = false;
260			bool flag_debug_parser = false;
261			bool flag_nolatches = false;
262			bool flag_nomeminit = false;
263			bool flag_nomem2reg = false;
264			bool flag_mem2reg = false;
265			bool flag_ppdump = false;
266			bool flag_nopp = false;
267			bool flag_nodpi = false;
268			bool flag_noopt = false;
269			bool flag_icells = false;
270			bool flag_pwires = false;
271			bool flag_nooverwrite = false;
272			bool flag_overwrite = false;
273			bool flag_defer = false;
274			bool flag_noblackbox = false;
275			bool flag_nowb = false;
276			bool flag_nosynthesis = false;
277			bool flag_yydebug = false;
278			bool flag_relative_share = false;
279			define_map_t defines_map;
280	
281			std::list<std::string> include_dirs;
282			std::list<std::string> attributes;
283	
284			ParseMode parse_mode = {};
285			ParseState parse_state = {};
286			parse_mode.sv = false;
287			parse_mode.formal = false;
288			parse_mode.noassert = false;
289			parse_mode.noassume = false;
290			parse_mode.norestrict = false;
291			parse_mode.assume_asserts = false;
292			parse_mode.assert_assumes = false;
293			parse_mode.lib = false;
294			parse_mode.specify = false;
295			parse_state.default_nettype_wire = true;
296	
297			args.insert(args.begin()+1, verilog_defaults.begin(), verilog_defaults.end());
298	
299			size_t argidx;
300			for (argidx = 1; argidx < args.size(); argidx++) {
301				std::string arg = args[argidx];
302				if (arg == "-sv") {
303					parse_mode.sv = true;
304					continue;
305				}
306				if (arg == "-formal") {
307					parse_mode.formal = true;
308					continue;
309				}
310				if (arg == "-nosynthesis") {
311					flag_nosynthesis = true;
312					continue;
313				}
314				if (arg == "-noassert") {
315					parse_mode.noassert = true;
316					continue;
317				}
318				if (arg == "-noassume") {
319					parse_mode.noassume = true;
320					continue;
321				}
322				if (arg == "-norestrict") {
323					parse_mode.norestrict = true;
324					continue;
325				}
326				if (arg == "-assume-asserts") {
327					parse_mode.assume_asserts = true;
328					continue;
329				}
330				if (arg == "-assert-assumes") {
331					parse_mode.assert_assumes = true;
332					continue;
333				}
334				if (arg == "-nodisplay") {
335					flag_nodisplay = true;
336					continue;
337				}
338				if (arg == "-debug") {
339					flag_dump_ast1 = true;
340					flag_dump_ast2 = true;
341					flag_dump_vlog1 = true;
342					flag_dump_vlog2 = true;
343					flag_debug_lexer = true;
344					flag_debug_parser = true;
345					continue;
346				}
347				if (arg == "-dump_ast1") {
348					flag_dump_ast1 = true;
349					continue;
350				}
351				if (arg == "-dump_ast2") {
352					flag_dump_ast2 = true;
353					continue;
354				}
355				if (arg == "-no_dump_ptr") {
356					flag_no_dump_ptr = true;
357					continue;
358				}
359				if (arg == "-dump_vlog1") {
360					flag_dump_vlog1 = true;
361					continue;
362				}
363				if (arg == "-dump_vlog2") {
364					flag_dump_vlog2 = true;
365					continue;
366				}
367				if (arg == "-dump_rtlil") {
368					flag_dump_rtlil = true;
369					continue;
370				}
371				if (arg == "-yydebug") {
372					flag_yydebug = true;
373					flag_debug_lexer = true;
374					flag_debug_parser = true;
375					continue;
376				}
377				if (arg == "-nolatches") {
378					flag_nolatches = true;
379					continue;
380				}
381				if (arg == "-nomeminit") {
382					flag_nomeminit = true;
383					continue;
384				}
385				if (arg == "-nomem2reg") {
386					flag_nomem2reg = true;
387					continue;
388				}
389				if (arg == "-mem2reg") {
390					flag_mem2reg = true;
391					continue;
392				}
393				if (arg == "-ppdump") {
394					flag_ppdump = true;
395					continue;
396				}
397				if (arg == "-nopp") {
398					flag_nopp = true;
399					continue;
400				}
401				if (arg == "-nodpi") {
402					flag_nodpi = true;
403					continue;
404				}
405				if (arg == "-noblackbox") {
406					flag_noblackbox = true;
407					continue;
408				}
409				if (arg == "-lib") {
410					parse_mode.lib = true;
411					defines_map.add("BLACKBOX", "");
412					continue;
413				}
414				if (arg == "-nowb") {
415					flag_nowb = true;
416					continue;
417				}
418				if (arg == "-specify") {
419					parse_mode.specify = true;
420					continue;
421				}
422				if (arg == "-noopt") {
423					flag_noopt = true;
424					continue;
425				}
426				if (arg == "-icells") {
427					flag_icells = true;
428					continue;
429				}
430				if (arg == "-pwires") {
431					flag_pwires = true;
432					continue;
433				}
434				if (arg == "-ignore_redef" || arg == "-nooverwrite") {
435					flag_nooverwrite = true;
436					flag_overwrite = false;
437					continue;
438				}
439				if (arg == "-overwrite") {
440					flag_nooverwrite = false;
441					flag_overwrite = true;
442					continue;
443				}
444				if (arg == "-defer") {
445					flag_defer = true;
446					continue;
447				}
448				if (arg == "-noautowire") {
449					parse_state.default_nettype_wire = false;
450					continue;
451				}
452				if (arg == "-setattr" && argidx+1 < args.size()) {
453					attributes.push_back(RTLIL::escape_id(args[++argidx]));
454					continue;
455				}
456				if (arg == "-relativeshare") {
457					flag_relative_share = true;
458					log_experimental("read_verilog -relativeshare");
459					continue;
460				}
461				if (arg == "-D" && argidx+1 < args.size()) {
462					std::string name = args[++argidx], value;
463					size_t equal = name.find('=');
464					if (equal != std::string::npos) {
465						value = name.substr(equal+1);
466						name = name.substr(0, equal);
467					}
468					defines_map.add(name, value);
469					continue;
470				}
471				if (arg.compare(0, 2, "-D") == 0) {
472					size_t equal = arg.find('=', 2);
473					std::string name = arg.substr(2, equal-2);
474					std::string value;
475					if (equal != std::string::npos)
476						value = arg.substr(equal+1);
477					defines_map.add(name, value);
478					continue;
479				}
480				if (arg == "-I" && argidx+1 < args.size()) {
481					include_dirs.push_back(args[++argidx]);
482					continue;
483				}
484				if (arg.compare(0, 2, "-I") == 0) {
485					include_dirs.push_back(arg.substr(2));
486					continue;
487				}
488				break;
489			}
490	
491			if (parse_mode.formal || !flag_nosynthesis)
492				defines_map.add(parse_mode.formal ? "FORMAL" : "SYNTHESIS", "1");
493	
494			extra_args(f, filename, args, argidx);
495	
496			log_header(design, "Executing Verilog-2005 frontend: %s\n", filename);
497	
498			log("Parsing %s%s input from `%s' to AST representation.\n",
499					parse_mode.formal ? "formal " : "", parse_mode.sv ? "SystemVerilog" : "Verilog", filename.c_str());
500	
501			if (flag_relative_share) {
502				auto share_path = proc_share_dirname();
503				if (filename.substr(0, share_path.length()) == share_path)
504					filename = std::string("+/") + filename.substr(share_path.length());
505				log("new filename %s\n", filename.c_str());
506			}
507			AST::sv_mode_but_global_and_used_for_literally_one_condition = parse_mode.sv;
508			std::string code_after_preproc;
509	
510			parse_state.lexin = f;
511			if (!flag_nopp) {
512				code_after_preproc = frontend_verilog_preproc(*f, filename, defines_map, *design->verilog_defines, include_dirs, parse_state, parse_mode);
513				if (flag_ppdump)
514					log("-- Verilog code after preprocessor --\n%s-- END OF DUMP --\n", code_after_preproc);
515				parse_state.lexin = new std::istringstream(code_after_preproc);
516			}
517	
518			auto filename_shared = std::make_shared<std::string>(filename);
519			auto top_loc = Location();
520			top_loc.begin.filename = filename_shared;
521			parse_state.current_ast = new AST::AstNode(top_loc, AST::AST_DESIGN);
522			VerilogLexer lexer(&parse_state, &parse_mode, filename_shared);
523			frontend_verilog_yy::parser parser(&lexer, &parse_state, &parse_mode);
524			lexer.set_debug(flag_debug_lexer);
525			parser.set_debug_level(flag_debug_parser ? 1 : 0);
526	
527			// make package typedefs available to parser
528			add_package_types(parse_state.pkg_user_types, design->verilog_packages);
529	
530			UserTypeMap global_types_map;
531			for (auto& def : design->verilog_globals) {
532				if (def->type == AST::AST_TYPEDEF) {
533					global_types_map[def->str] = def.get();
534				}
535			}
536	
537			log_assert(parse_state.user_type_stack.empty());
538			// use previous global typedefs as bottom level of user type stack
539			parse_state.user_type_stack.push_back(std::move(global_types_map));
540			// add a new empty type map to allow overriding existing global definitions
541			parse_state.user_type_stack.push_back(UserTypeMap());
542	
543			if (flag_yydebug) {
544				lexer.set_debug(true);
545				parser.set_debug_level(1);
546			}
547			parser.parse();
548			// frontend_verilog_yyset_lineno(1);
549	
550			for (auto &child : parse_state.current_ast->children) {
551				if (child->type == AST::AST_MODULE)
552					for (auto &attr : attributes)
553						if (child->attributes.count(attr) == 0)
554							child->attributes[attr] = AST::AstNode::mkconst_int(top_loc, 1, false);
555			}
556	
557			if (flag_nodpi)
558				error_on_dpi_function(parse_state.current_ast);
559	
560			AST::process(design, parse_state.current_ast, flag_nodisplay, flag_dump_ast1, flag_dump_ast2, flag_no_dump_ptr, flag_dump_vlog1, flag_dump_vlog2, flag_dump_rtlil, flag_nolatches,
561					flag_nomeminit, flag_nomem2reg, flag_mem2reg, flag_noblackbox, parse_mode.lib, flag_nowb, flag_noopt, flag_icells, flag_pwires, flag_nooverwrite, flag_overwrite, flag_defer, parse_state.default_nettype_wire);
562	
563	
564			if (!flag_nopp)
565				delete parse_state.lexin;
566	
567			// only the previous and new global type maps remain
568			log_assert(parse_state.user_type_stack.size() == 2);
569			parse_state.user_type_stack.clear();
570	
571			delete parse_state.current_ast;
572			parse_state.current_ast = NULL;
573	
574			log("Successfully finished Verilog frontend.\n");
575		}
576	} VerilogFrontend;
577	
578	struct VerilogDefaults : public Pass {
579		VerilogDefaults() : Pass("verilog_defaults", "set default options for read_verilog") { }
580		void help() override
581		{
582			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
583			log("\n");
584			log("    verilog_defaults -add [options]\n");
585			log("\n");
586			log("Add the specified options to the list of default options to read_verilog.\n");
587			log("\n");
588			log("\n");
589			log("    verilog_defaults -clear\n");
590			log("\n");
591			log("Clear the list of Verilog default options.\n");
592			log("\n");
593			log("\n");
594			log("    verilog_defaults -push\n");
595			log("    verilog_defaults -pop\n");
596			log("\n");
597			log("Push or pop the list of default options to a stack. Note that -push does\n");
598			log("not imply -clear.\n");
599			log("\n");
600		}
601		void execute(std::vector<std::string> args, RTLIL::Design*) override
602		{
603			if (args.size() < 2)
604				cmd_error(args, 1, "Missing argument.");
605	
606			if (args[1] == "-add") {
607				verilog_defaults.insert(verilog_defaults.end(), args.begin()+2, args.end());
608				return;
609			}
610	
611			if (args.size() != 2)
612				cmd_error(args, 2, "Extra argument.");
613	
614			if (args[1] == "-clear") {
615				verilog_defaults.clear();
616				return;
617			}
618	
619			if (args[1] == "-push") {
620				verilog_defaults_stack.push_back(verilog_defaults);
621				return;
622			}
623	
624			if (args[1] == "-pop") {
625				if (verilog_defaults_stack.empty()) {
626					verilog_defaults.clear();
627				} else {
628					verilog_defaults.swap(verilog_defaults_stack.back());
629					verilog_defaults_stack.pop_back();
630				}
631				return;
632			}
633		}
634	} VerilogDefaults;
635	
636	struct VerilogDefines : public Pass {
637		VerilogDefines() : Pass("verilog_defines", "define and undefine verilog defines") { }
638		void help() override
639		{
640			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
641			log("\n");
642			log("    verilog_defines [options]\n");
643			log("\n");
644			log("Define and undefine verilog preprocessor macros.\n");
645			log("\n");
646			log("    -Dname[=definition]\n");
647			log("        define the preprocessor symbol 'name' and set its optional value\n");
648			log("        'definition'\n");
649			log("\n");
650			log("    -Uname[=definition]\n");
651			log("        undefine the preprocessor symbol 'name'\n");
652			log("\n");
653			log("    -reset\n");
654			log("        clear list of defined preprocessor symbols\n");
655			log("\n");
656			log("    -list\n");
657			log("        list currently defined preprocessor symbols\n");
658			log("\n");
659		}
660		void execute(std::vector<std::string> args, RTLIL::Design *design) override
661		{
662			size_t argidx;
663			for (argidx = 1; argidx < args.size(); argidx++) {
664				std::string arg = args[argidx];
665				if (arg == "-D" && argidx+1 < args.size()) {
666					std::string name = args[++argidx], value;
667					size_t equal = name.find('=');
668					if (equal != std::string::npos) {
669						value = name.substr(equal+1);
670						name = name.substr(0, equal);
671					}
672					design->verilog_defines->add(name, value);
673					continue;
674				}
675				if (arg.compare(0, 2, "-D") == 0) {
676					size_t equal = arg.find('=', 2);
677					std::string name = arg.substr(2, equal-2);
678					std::string value;
679					if (equal != std::string::npos)
680						value = arg.substr(equal+1);
681					design->verilog_defines->add(name, value);
682					continue;
683				}
684				if (arg == "-U" && argidx+1 < args.size()) {
685					std::string name = args[++argidx];
686					design->verilog_defines->erase(name);
687					continue;
688				}
689				if (arg.compare(0, 2, "-U") == 0) {
690					std::string name = arg.substr(2);
691					design->verilog_defines->erase(name);
692					continue;
693				}
694				if (arg == "-reset") {
695					design->verilog_defines->clear();
696					continue;
697				}
698				if (arg == "-list") {
699					design->verilog_defines->log();
700					continue;
701				}
702				break;
703			}
704	
705			if (args.size() != argidx)
706				cmd_error(args, argidx, "Extra argument.");
707		}
708	} VerilogDefines;
709	
710	static void parse_file_list(const std::string &file_list_path, RTLIL::Design *design, bool relative_to_file_list_path)
711	{
712		std::ifstream flist(file_list_path);
713		if (!flist.is_open()) {
714			log_error("Verilog file list file does not exist");
715			exit(1);
716		}
717	
718		std::filesystem::path file_list_parent_dir = std::filesystem::path(file_list_path).parent_path();
719	
720		std::string v_file_name;
721		while (std::getline(flist, v_file_name)) {
722			if (v_file_name.empty()) {
723				continue;
724			}
725	
726			std::filesystem::path verilog_file_path;
727			if (relative_to_file_list_path) {
728				verilog_file_path = file_list_parent_dir / v_file_name;
729			} else {
730				verilog_file_path = std::filesystem::current_path() / v_file_name;
731			}
732	
733			bool is_sv = (verilog_file_path.extension() == ".sv");
734	
735			std::vector<std::string> read_verilog_cmd = {"read_verilog", "-defer"};
736			if (is_sv) {
737				read_verilog_cmd.push_back("-sv");
738			}
739			read_verilog_cmd.push_back(verilog_file_path.string());
740			Pass::call(design, read_verilog_cmd);
741		}
742	
743		flist.close();
744	}
745	
746	struct VerilogFileList : public Pass {
747		VerilogFileList() : Pass("read_verilog_file_list", "parse a Verilog file list") {}
748		void help() override
749		{
750			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
751			log("\n");
752			log("    read_verilog_file_list [options]\n");
753			log("\n");
754			log("Parse a Verilog file list, and pass the list of Verilog files to read_verilog\n");
755			log("command\n");
756			log("\n");
757			log("    -F file_list_path\n");
758			log("        File list file contains list of Verilog files to be parsed, any path is\n");
759			log("        treated relative to the file list file\n");
760			log("\n");
761			log("    -f file_list_path\n");
762			log("        File list file contains list of Verilog files to be parsed, any path is\n");
763			log("        treated relative to current working directroy\n");
764			log("\n");
765		}
766	
767		void execute(std::vector<std::string> args, RTLIL::Design *design) override
768		{
769			size_t argidx;
770			for (argidx = 1; argidx < args.size(); argidx++) {
771				std::string arg = args[argidx];
772				if (arg == "-F" && argidx + 1 < args.size()) {
773					std::string file_list_path = args[++argidx];
774					parse_file_list(file_list_path, design, true);
775					continue;
776				}
777				if (arg == "-f" && argidx + 1 < args.size()) {
778					std::string file_list_path = args[++argidx];
779					parse_file_list(file_list_path, design, false);
780					continue;
781				}
782				break;
783			}
784	
785			extra_args(args, argidx, design, false);
786		}
787	} VerilogFilelist;
788	
789	YOSYS_NAMESPACE_END
