23	 *  Thus this frontend does not generate RTLIL code directly but creates an
24	 *  AST directly from the Verilog parse tree and then passes this AST to
25	 *  the AST frontend library.
26	 *
27	 *  ---
28	 *
29	 *  A simple lexer for Verilog code. Non-preprocessor compiler directives are
30	 *  handled here. The preprocessor stuff is handled in preproc.cc. Everything
31	 *  else is left to the bison parser (see verilog_parser.y).
32	 *
33	 */
34	
35	%option c++
36	%option yyclass="VerilogLexer"
37	%option noyywrap
38	%option nounput
39	%option yylineno
40	%option prefix="frontend_verilog_yy"
41	
42	%{
43	
44	#ifdef __clang__
45	// bison generates code using the 'register' storage class specifier
46	#pragma clang diagnostic ignored "-Wdeprecated-register"
47	// flex generates weirdly-indented code
48	#pragma clang diagnostic ignored "-Wmisleading-indentation"
49	#endif
50	
51	#include "frontends/verilog/verilog_lexer.h"
52	#include "frontends/ast/ast.h"
53	#include "frontends/verilog/verilog_location.h"
54	#include "kernel/log.h"
55	#include <vector>
56	#include <memory>
57	
58	USING_YOSYS_NAMESPACE
59	using namespace AST;
60	using namespace VERILOG_FRONTEND;
61	using parser = frontend_verilog_yy::parser;
62	
63	YOSYS_NAMESPACE_BEGIN
64	#undef YY_DECL
65	#define YY_DECL parser::symbol_type VerilogLexer::nextToken()
66	
67	#undef yyterminate
68	#define yyterminate() return terminate()
69	
70	YOSYS_NAMESPACE_END
71	
72	#define SV_KEYWORD(_tok) \
73		if (mode->sv) return _tok; \
74		log("Lexer warning: The SystemVerilog keyword `%s' (at %s:%d) is not "\
75				"recognized unless read_verilog is called with -sv!\n", YYText(), \
76				current_filename->c_str(), yylineno); \
77		string_t val = std::make_unique<std::string>(std::string("\\") + YYText()); \
78		return parser::make_TOK_ID(std::move(val), out_loc);
79	
80	#define NON_KEYWORD() \
81		string_t val = std::make_unique<std::string>(std::string("\\") + YYText()); \
82		return parser::make_TOK_ID(std::move(val), out_loc);
83	
84	
85	#define YY_USER_ACTION \
86		out_loc.step(); \
87		for(int i = 0; YYText()[i] != '\0'; ++i){ \
88			if(YYText()[i] == '\n') { \
89				out_loc.lines(); \
90			} \
91			else { \
92				out_loc.columns(); \
93			} \
94		} \
95		out_loc.begin.filename = current_filename; \
96		out_loc.end.filename = current_filename;
97	
98	#define YY_BREAK \
99	    break;
100	
101	#undef YY_BUF_SIZE
102	#define YY_BUF_SIZE 65536
103	
104	static bool isUserType(ParseState* extra, std::string &s)
105	{
106		// check current scope then outer scopes for a name
107		for (auto it = extra->user_type_stack.rbegin(); it != extra->user_type_stack.rend(); ++it) {
108			if (it->count(s) > 0) {
109					return true;
110			}
111		}
112		return false;
113	}
114	
115	parser::symbol_type char_tok(char c, parser::location_type loc) {
116		switch (c) {
117			case '!': return parser::make_TOK_EXCL(loc);
118			case '#': return parser::make_TOK_HASH(loc);
119			case '%': return parser::make_TOK_PERC(loc);
120			case '&': return parser::make_TOK_AMP(loc);
121			case '(': return parser::make_TOK_LPAREN(loc);
122			case ')': return parser::make_TOK_RPAREN(loc);
123			case '*': return parser::make_TOK_ASTER(loc);
124			case '+': return parser::make_TOK_PLUS(loc);
125			case ',': return parser::make_TOK_COMMA(loc);
126			case '-': return parser::make_TOK_MINUS(loc);
127			case '.': return parser::make_TOK_DOT(loc);
128			case '/': return parser::make_TOK_SLASH(loc);
129			case ':': return parser::make_TOK_COL(loc);
130			case ';': return parser::make_TOK_SEMICOL(loc);
131			case '<': return parser::make_TOK_LT(loc);
132			case '=': return parser::make_TOK_EQ(loc);
133			case '>': return parser::make_TOK_GT(loc);
134			case '?': return parser::make_TOK_QUE(loc);
135			case '@': return parser::make_TOK_AT(loc);
136			case '[': return parser::make_TOK_LBRA(loc);
137			case ']': return parser::make_TOK_RBRA(loc);
138			case '^': return parser::make_TOK_CARET(loc);
139			case '_': return parser::make_TOK_UNDER(loc);
140			case '{': return parser::make_TOK_LCURL(loc);
141			case '|': return parser::make_TOK_PIPE(loc);
142			case '}': return parser::make_TOK_RCURL(loc);
143			case '~': return parser::make_TOK_TILDE(loc);
144			case 'n': return parser::make_TOK_n(loc);
145			case 'p': return parser::make_TOK_p(loc);
146			case 'x': return parser::make_TOK_x(loc);
147			case 'z': return parser::make_TOK_z(loc);
148			case 0: return parser::make_FRONTEND_VERILOG_YYEOF(loc);
149			default:
150				return parser::make_ch_t(c, loc);
151		}
152	}
153	static bool is_hex_dig(char c, int *val, parser::location_type loc)
154	{
155		if ('0' <= c && c <= '9') {
156			*val = c - '0';
157			return true;
158		} else if ('a' <= c && c <= 'f') {
159			*val = c - 'a' + 0xA;
160			return true;
161		} else if ('A' <= c && c <= 'F') {
162			*val = c - 'A' + 0xA;
163			return true;
164		} else if (c == 'x' || c == 'X' || c == 'z' || c == 'Z' || c == '?') {
165			log_file_warning(*loc.begin.filename, loc.begin.line, "'%c' not a valid digit in hex escape sequence.\n", c);
166			*val = 0; // not semantically valid in hex escape...
167			return true; // ...but still processed as part of hex token
168		}
169	
170		return false;
171	}
172	
173	static bool is_oct_dig(char c, int *val, parser::location_type loc)
174	{
175		if ('0' <= c && c <= '7') {
176			*val = c - '0';
177			return true;
178		} else if (c == 'x' || c == 'X' || c == 'z' || c == 'Z' || c == '?') {
179			log_file_warning(*loc.begin.filename, loc.begin.line, "'%c' not a valid digit in octal escape sequence.\n", c);
180			*val = 0; // not semantically valid in octal escape...
181			return true; // ...but still processed as part of octal token
182		}
183	
184		return false;
185	}
186	
187	static parser::symbol_type process_str(char *str, int len, bool triple, parser::location_type loc)
188	{
189		char *in, *out; // Overwrite input buffer: flex manual states "Actions
190			// are free to modify 'yytext' except for lengthening it".
191	
192		for (in = str, out = str; in < str + len; in++)
193			switch (*in) {
194			case '\n':
195			case '\r':
196				if (in + 1 < str + len && (in[1] ^ *in) == ('\n' ^ '\r'))
197					in++;
198				if (!triple)
199					log_file_warning(*loc.begin.filename, loc.begin.line, "Multi-line string literals should be triple-quoted or escaped.\n");
200				*out++ = '\n';
201				break;
202			case '\\':
203				in++;
204				log_assert(in < str + len);
205				switch (*in) {
206				case 'a':
207					*out++ = '\a';
208					break;
209				case 'f':
210					*out++ = '\f';
211					break;
212				case 'n':
213					*out++ = '\n';
214					break;
215				case 'r': /* not part of IEEE-1800 2023, but seems
216					     like a good idea to support it anyway */
217					*out++ = '\r';
218					break;
219				case 't':
220					*out++ = '\t';

